distr_table <- distr() %>%
  arrange(!default, param) %>%
  select(distr, distr_title, dim, type, param) %>%
  group_by(distr, distr_title, dim, type) %>%
  summarize(param = paste(param, collapse = ", ")) %>%
  ungroup() %>%
  mutate(dim = recode(dim, "uni" = "Uni.", "multi" = "Multi.")) %>%
  mutate(type = recode(type, "binary" = "Binary", "cat" = "Categorical", "circular" = "Circular", "comp" = "Compositional", "count" = "Count", "duration" = "Duration", "integer" = "Integer", "interval" = "Interval", "ranking" = "Ranking", "real" = "Real")) %>%
  mutate(distr = paste0("\\code{", distr, "}")) %>%
  mutate(param = paste0("\\code{", param, "}")) %>%
  rename(c("Label" = "distr", "Distribution" = "distr_title", "Dim." = "dim", "Data Type" = "type", "Parametrizations" = "param")) %>%
  arrange(Label)

